const payload = $json.body ?? $json;
const required = ['cnpj_cliente', 'cliente_nome', 'data_inicio', 'modelo_negocio', 'servico', 'origem_comercial'];
const errors = [];
for (const field of required) {
  if (payload[field] === undefined || payload[field] === null || payload[field] === '') {
    errors.push(`Campo obrigatorio ausente: ${field}`);
  }
}
const modelosAceitos = ['Infoproduto', 'Lead Gen', 'E-Commerce'];
const servicosAceitos = new Set(['Tr\u00e1fego pago', 'Trafego pago', 'Site', 'Agente IA']);
if (payload.modelo_negocio && !modelosAceitos.includes(payload.modelo_negocio)) {
  errors.push('modelo_negocio invalido');
}
if (payload.servico && !Array.isArray(payload.servico)) {
  errors.push('servico deve ser array');
}
if (Array.isArray(payload.servico)) {
  const invalidos = payload.servico.filter((item) => !servicosAceitos.has(item));
  if (invalidos.length) {
    errors.push(`servico invalido: ${invalidos.join(', ')}`);
  }
}
if (payload.data_inicio && !/^\d{4}-\d{2}-\d{2}$/.test(payload.data_inicio)) {
  errors.push('data_inicio deve estar em YYYY-MM-DD');
}
if (errors.length) {
  return [{ json: { is_valid: false, statusCode: 400, error: 'Payload invalido', details: errors, received_payload: payload } }];
}
return [{ json: { is_valid: true, payload } }];

const payload = $json.payload;
const normalizarTexto = (value) => String(value ?? '').trim();
const normalizarNome = (value) => normalizarTexto(value).toLocaleLowerCase('pt-BR');
const cnpj_normalizado = String(payload.cnpj_cliente ?? '').replace(/\D/g, '');
const cliente_nome = normalizarTexto(payload.cliente_nome);
const servico = Array.isArray(payload.servico)
  ? payload.servico.map((item) => normalizarTexto(item) === 'Trafego pago' ? 'Tr\u00e1fego pago' : normalizarTexto(item))
  : [];
return [{ json: {
  cliente_nome,
  cliente_nome_normalizado: normalizarNome(cliente_nome),
  cnpj_original: payload.cnpj_cliente,
  cnpj_normalizado,
  data_inicio: payload.data_inicio,
  modelo_negocio: payload.modelo_negocio,
  servico,
  origem_comercial: normalizarTexto(payload.origem_comercial),
  responsavel_geral_email: payload.responsavel_geral_email ? normalizarTexto(payload.responsavel_geral_email).toLowerCase() : null,
  observacoes: `CNPJ normalizado: ${cnpj_normalizado}`,
  raw_payload: payload,
  active_statuses: ['Em andamento', 'N\u00e3o iniciado', 'Bloqueado']
} }];

const contexto = $('[Onb A2.1] Normalizar Contexto').first().json;
const rows = $input.all();
const pickPlain = (prop) => {
  if (!prop) return '';
  if (prop.title?.length) return prop.title.map((item) => item.plain_text || '').join('').trim();
  if (prop.rich_text?.length) return prop.rich_text.map((item) => item.plain_text || '').join('').trim();
  return '';
};
const pickSelect = (prop) => prop?.select?.name ?? '';
const activeStatuses = new Set(contexto.active_statuses);
const duplicate = rows.find((item) => {
  const props = item.json.properties || {};
  const nome = pickPlain(props['Cliente']);
  const nomeNormalizado = nome.trim().toLocaleLowerCase('pt-BR');
  const status = pickSelect(props['Status']);
  return activeStatuses.has(status) && nomeNormalizado === contexto.cliente_nome_normalizado;
});
if (!duplicate) {
  return [{ json: { ...contexto, has_duplicate: false } }];
}
return [{ json: {
  ...contexto,
  has_duplicate: true,
  duplicate_page_id: duplicate.json.id,
  duplicate_status: pickSelect(duplicate.json.properties?.Status),
  duplicate_message: 'Onboarding ativo ja existe para este cliente.'
} }];

const contexto = $('[Onb A2.1] Detectar Duplicidade').first().json;
const users = $input.all().map((item) => item.json);
const responsavel = contexto.responsavel_geral_email
  ? users.find((user) => String(user.person?.email || '').toLowerCase() === contexto.responsavel_geral_email)
  : null;
return [{ json: {
  ...contexto,
  responsavel_geral_id: responsavel?.id ?? null,
  schema_hints: {
    cliente_relation_inverse: 'Etapas de Onboarding',
    etapas_title_property: 'Nome da etapa'
  },
  cliente_properties: {
    cliente_nome: contexto.cliente_nome,
    status: 'Em andamento',
    data_inicio: contexto.data_inicio,
    modelo_negocio: contexto.modelo_negocio,
    servico: contexto.servico,
    origem_comercial: contexto.origem_comercial,
    observacoes: contexto.observacoes,
    sla_primeira_entrega: 21,
    responsavel_geral_id: responsavel?.id ?? null
  }
} }];

const cliente = $('[Onb A2.1] Criar Cliente').first().json;
const contexto = $('[Onb A2.1] Resolver Responsavel Geral').first().json;
const raw = $input.first().json;
let dataset = raw;
if (typeof raw.data === 'string') {
  dataset = JSON.parse(raw.data);
} else if (typeof raw.json === 'string') {
  dataset = JSON.parse(raw.json);
}
const etapas = Array.isArray(dataset)
  ? dataset
  : Array.isArray(raw.etapas)
    ? raw.etapas
    : Array.isArray(dataset.etapas)
      ? dataset.etapas
      : null;
if (!Array.isArray(etapas)) {
  throw new Error('Arquivo etapas-a1.json invalido: esperado objeto com raw.etapas ou dataset.etapas');
}
// Contrato v1: data_inicio e date-only sem timezone; somamos dias em UTC para evitar drift de fuso.
const addDays = (isoDate, days) => {
  const dt = new Date(`${isoDate}T00:00:00.000Z`);
  dt.setUTCDate(dt.getUTCDate() + Number(days || 0));
  return dt.toISOString().slice(0, 10);
};
return etapas.map((etapa) => ({
  json: {
    cliente_page_id: cliente.id,
    cliente_nome: contexto.cliente_nome,
    data_inicio: contexto.data_inicio,
    etapa_nome: etapa.nome,
    sequencia: etapa.sequencia,
    tipo_etapa: etapa.tipo_etapa,
    aguardando: etapa.aguardando,
    prazo_dias: etapa.prazo_dias,
    inputs: etapa.inputs,
    output_dod: etapa.output_dod,
    data_prevista: addDays(contexto.data_inicio, etapa.prazo_dias),
    etapas_esperadas: etapas.length,
    raw_payload: contexto.raw_payload
  }
}));

const items = $input.all();
const contexto = $('[Onb A2.1] Resolver Responsavel Geral').first().json;
const cliente = $('[Onb A2.1] Criar Cliente').first().json;
const sucesso = [];
const falhas = [];
for (const item of items) {
  const payload = item.json || {};
  const hasError = Boolean(payload.error || payload.message || payload.stack);
  if (hasError && !payload.id) {
    falhas.push(payload.error?.message || payload.message || payload.description || JSON.stringify(payload));
  } else {
    sucesso.push(payload.id || payload);
  }
}
return [{ json: {
  cliente_page_id: cliente.id,
  cliente_nome: contexto.cliente_nome,
  cnpj_normalizado: contexto.cnpj_normalizado,
  raw_payload: contexto.raw_payload,
  etapas_esperadas: items[0]?.json?.etapas_esperadas ?? items.length,
  etapas_criadas: sucesso.length,
  etapas_falhas: falhas.length,
  falha_resumo: falhas.slice(0, 5).join(' | '),
  workflow_status: sucesso.length === (items[0]?.json?.etapas_esperadas ?? items.length) ? 'ok' : 'partial_failure'
} }];
